import json
from pathlib import Path
files=[]
for root in [Path('/home/adam-blumoff/.codex/sessions'), Path('/home/adam-blumoff/.codex/archived_sessions')]:
    if root.exists():
        files.extend(sorted(root.rglob('*.jsonl')))
print('files', len(files))
keywords=('go ahead','implement','review','autoreview','greptile','codex','plan','merge','branch','pr','pull main','manual qa','ci','green','cleanup','clean up','dead','tell me exactly','what are you doing','looks good','wait for')
for path in files:
    users=[]
    try:
        for line in path.read_text(errors='ignore').splitlines():
            if not line.strip():
                continue
            try:
                rec=json.loads(line)
            except Exception:
                continue
            payload=rec.get('payload') or {}
            role=None
            content=None
            if rec.get('type')=='response_item':
                if payload.get('type')=='message':
                    role=payload.get('role')
                    content=payload.get('content')
            elif rec.get('type')=='user_message':
                role='user'
                content=payload.get('message') or payload.get('content') or payload.get('text')
            if role!='user':
                continue
            texts=[]
            if isinstance(content, str):
                texts=[content]
            elif isinstance(content, list):
                for item in content:
                    if isinstance(item, dict):
                        t=item.get('text') or item.get('input_text')
                        if t:
                            texts.append(t)
                    elif isinstance(item, str):
                        texts.append(item)
            for t in texts:
                s=' '.join(t.split())
                if not s or s.startswith('# AGENTS.md instructions') or s.startswith('<environment_context>'):
                    continue
                if any(k in s.lower() for k in keywords):
                    users.append(s)
    except Exception as e:
        print('ERR', path, e)
        continue
    if users:
        print('\nFILE', path)
        for s in users[:20]:
            if len(s)>900:
                s=s[:900]+'...'
            print('  -', s)
        if len(users)>20:
            print('  ...', len(users)-20, 'more')
